   489→    ops[2].op = GRPC_OP_SEND_CLOSE_FROM_CLIENT;
   490→
   491→    ops[3].op = GRPC_OP_RECV_INITIAL_METADATA;
   492→    ops[3].data.recv_initial_metadata.recv_initial_metadata = &md_arr;
   493→
