   495→    grpc_slice details;
   496→    ops[4].op = GRPC_OP_RECV_STATUS_ON_CLIENT;
   497→    ops[4].data.recv_status_on_client.status = &status;
   498→    ops[4].data.recv_status_on_client.status_details = &details;
   499→
   500→    grpc_call_error cerr = grpc_call_start_batch(call, ops, 5, NULL, NULL);
   501→    if (cerr != GRPC_CALL_OK) {
   502→        SC_LOGE("gRPC start batch failed");
   503→        return false;
   504→    }
   505→
   506→    grpc_completion_queue_pluck(ctx->cq, NULL, gpr_inf_future(GPR_CLOCK_REALTIME), NULL);
   507→
   508→    /* Transform Protobuf to GraphQL JSON */
   509→    if (status != GRPC_STATUS_OK) {
   510→        gql_error(ctx, "Palette service error");
   511→        return false;
   512→    }
   513→
   514→    /* Omitted: decode response into ctx->response */
   515→
   516→    grpc_metadata_array_destroy(&md_arr);
   517→    grpc_byte_buffer_destroy(payload);
   518→    grpc_call_destroy(call);
   519→    grpc_channel_destroy(ch);
   520→    return true;
   521→}
   522→```
   523→
   524→---
   525→
   526→## 6  Versioning & Lifecycle
   527→
   528→- Every service exposes `/version` returning `{ "semver": "x.y.z", "git": "<sha>" }`.
   529→- GraphQL schemas are versioned via `@link(import:)` directives.
   530→- REST endpoints embed a major version in the URL (`/v1/`, `/v2/`).
   531→- Obsolete routes remain available for *one* minor version with deprecation
   532→  warnings in the response headers.
   533→
   534→---
   535→
   536→## 7  Observability & Resilience
   537→
   538→1. **Structured logging** (`JSON` when `LOG_FORMAT=json` env var is set).  
   539→2. **Metrics** exported via `/metrics` in Prometheus format.  
   540→3. **Tracing** instrumented through OpenTelemetry C SDK.  
   541→4. **Circuit-breaker** wrapper auto-generated around every gRPC stub.  
   542→5. **Rate-limiting** handled at the API Gateway using the Token-Bucket
   543→   algorithm (Redis backend).
   544→
   545→---
   546→
   547→## 8  Build & Deployment
   548→
   549→```
   550→$ mkdir build && cd build
   551→$ cmake -DCMAKE_BUILD_TYPE=Release ..
   552→$ make -j$(nproc)
   553→$ docker build -t synesthetic/palette:1.2.0 services/palette
   554→$ helm upgrade --install palette charts/palette
   555→```
   556→
   557→CI jobs run `clang-tidy`, `cppcheck`, unit tests (cmocka), and integration
   558→tests spun up with `testcontainers-c`.
   559→
   560→---
   561→
   562→## 9  Appendix – Compile Flags
   563→
