 -1 && errno != EINPROGRESS) {\n        SC_LOG(LOG_ERR, \"connect(%s): %m\", socket_path);\n        close(fd);\n        return NULL;\n    }\n\n    if (rc == -1) {\n        /* Wait for connect completion */\n        struct pollfd pfd = { .fd = fd, .events = POLLOUT };\n        rc                = poll(&pfd, 1, timeout_ms);\n        if (rc == 0) {\n            errno = ETIMEDOUT;\n            close(fd);\n            return NULL;\n        }\n        if (rc < 0) {\n            close(fd);\n            return NULL;\n        }\n        /* Check connection result */\n        int err;\n        socklen_t len = sizeof(err);\n        if (getsockopt(fd, SOL_SOCKET, SO_ERROR, &err, &len) == -1 || err) {\n            if (!err)\n                err = errno;\n            errno = err;\n            close(fd);\n            return NULL;\n        }\n    }\n\n    sc_ipc_endpoint_t *ep = endpoint_new(fd, false, socket_path);\n    if (!ep) {\n        close(fd);\n        return NULL;\n    }\n    return ep;\n}\n\nssize_t\nsc_ipc_send(const sc_ipc_endpoint_t *endpoint, const void *buf, size_t len,\n            int flags /* future use */)\n{\n    (void)flags;\n\n    if (!endpoint || !buf || len > SC_IPC_MAX_PAYLOAD) {\n        errno = EINVAL;\n        return -1;\n    }\n\n    uint8_t header[4];\n    uint32_t be_len = htonl((uint32_t)len);\n    memcpy(header, &be_len, sizeof(be_len));\n\n    struct iovec iov[2] = {\n        { .iov_base = header, .iov_len = sizeof(header) },\n        { .iov_base = (void *)buf, .iov_len = len },\n    };\n\n    /* Use writev for fewer syscalls */\n    ssize_t sent = writev(endpoint->fd, iov, 2);\n    if (sent == -1 && (errno == EAGAIN || errno == EWOULDBLOCK)) {\n        /* Fallback to blocking loop */\n        if (write_full(endpoint->fd, header, sizeof(header)) == -1)\n            return -1;\n        if (write_full(endpoint->fd, buf, len) == -1)\n            return -1;\n        sent = sizeof(header) + (ssize_t)len;\n    } else if (sent != (ssize_t)sizeof(header) + (ssize_t)len) {\n        /* Partial write not expected when socket is blocking; treat as error. */\n        errno = EIO;\n        return -1;\n    }\n\n    return sent;\n}\n\nssize_t\nsc_ipc_recv(const sc_ipc_endpoint_t *endpoint, void **buf_out, int timeout_ms)\n{\n    if (!endpoint || !buf_out) {\n        errno = EINVAL;\n        return -1;\n    }\n\n    uint32_t be_len;\n    int rc = read_full_deadline(endpoint->fd, (uint8_t *)&be_len,\n                                sizeof(be_len), timeout_ms);\n    if (rc == -2) { /* timeout */\n        return 0;\n    }\n    if (rc == -1) {\n        return -1;\n    }\n\n    uint32_t len = ntohl(be_len);\n    if (len == 0 || len > SC_IPC_MAX_PAYLOAD) {\n        errno = EMSGSIZE;\n        return -1;\n    }\n\n    uint8_t *payload = malloc(len + 1);\n    if (!payload) {\n        return -1;\n    }\n\n    rc = read_full_deadline(endpoint->fd, payload, len, timeout_ms);\n    if (rc == -2) {\n        free(payload);\n        return 0; /* timeout waiting for rest */\n    }\n    if (rc == -1) {\n        free(payload);\n        return -1;\n    }\n\n    payload[len] = '\\0'; /* NUL-terminate for quick string use (optional) */\n    *buf_out     = payload;\n    return (ssize_t)len;\n}\n\nvoid\nsc_ipc_endpoint_destroy(sc_ipc_endpoint_t *endpoint)\n{\n    if (!endpoint)\n        return;\n\n    if (endpoint->fd != -1)\n        close(endpoint->fd);\n\n    /* Remove socket file only for server listening endpoints. */\n    if (endpoint->is_server && *endpoint->path)\n        unlink(endpoint->path);\n\n    free(endpoint);\n}\n\n/* Convenience wrapper to send a NUL-terminated string. Returns bytes sent. */\nssize_t\nsc_ipc_send_str(const sc_ipc_endpoint_t *endpoint, const char *str)\n{\n    if (!str)\n        return -1;\n    return sc_ipc_send(endpoint, str, strlen(str), 0);\n}\n\n/* Graceful shutdown helper: shuts down write side then waits for peer EOF. */\nint\nsc_ipc_shutdown(sc_ipc_endpoint_t *endpoint, int deadline_ms)\n{\n    if (!endpoint)\n        return -1;\n\n    shutdown(endpoint->fd, SHUT_WR);\n\n    struct pollfd pfd = { .fd = endpoint->fd, .events = POLLIN };\n    int rc            = poll(&pfd, 1, deadline_ms);\n    if (rc <= 0)\n        return rc; /* 0 = timeout, -1 = error */\n\n    /* Drain any remaining input (could also just close). */\n    char tmp[256];\n    while (read(endpoint->fd, tmp, sizeof(tmp)) > 0)\n        ;\n    return 0;\n}\n\n/* -------------------------------------------------------------------------\n * Version info (returned via sc_ipc_version_string()) so that dynamically\n * loaded plugins can verify ABI compatibility at runtime.\n * -------------------------------------------------------------------------*/\n#define SC_IPC_VERSION_STR \"1.0.0\"\n\nconst char *\nsc_ipc_version_string(void)\n{\n    return SC_IPC_VERSION_STR;\n}\n```", "numLines": 443, "startLine": 1, "totalLines": 443}}

1→/*
     2→ * SynestheticCanvas - API Gateway
     3→ * --------------------------------
     4→ * service_client.c
     5→ *
     6→ * A production-grade, thread-safe service client wrapper around libcurl that is
     7→ * responsible for communicating with downstream creative micro-services
     8→ * (palette, texture, audio, narrative).  The client provides:
     9→ *
    10→ *  • Configurable per-service base URLs loaded from environment variables
    11→ *  • Automatic request instrumentation (request / failure counters)
    12→ *  • Exponential-back-off retries with jitter
    13→ *  • JSON parsing (cJSON) and basic validation
    14→ *  • Centralised structured logging
    15→ *
    16→ * Author  : SynestheticCanvas Core Team
    17→ * License : MIT
    18→ */
    19→
    20→#include "service_client.h"
    21→
    22→#include <curl/curl.h>
    23→#include <errno.h>
    24→#include <inttypes.h>
    25→#include <pthread.h>
    26→#include <signal.h>
    27→#include <stdatomic.h>
    28→#include <stdio.h>
    29→#include <stdlib.h>
    30→#include <string.h>
    31→#include <time.h>
    32→
    33→/* -------------------------------------------------------------------------
    34→ * Local Macros & Helpers
    35→ * ------------------------------------------------------------------------- */
    36→#define SC_DEFAULT_TIMEOUT_MS 5000
    37→#define SC_DEFAULT_RETRIES        3
    38→#define SC_DEFAULT_BACKOFF_MS   250
    39→#define SC_BACKOFF_FACTOR       2.0
    40→
    41→#define SC_ENV_PALETTE_URL   "SC_PALETTE_SERVICE_URL"
    42→#define SC_ENV_TEXTURE_URL   "SC_TEXTURE_SERVICE_URL"
    43→#define SC_ENV_AUDIO_URL     "SC_AUDIO_SERVICE_URL"
    44→#define SC_ENV_NARRATIVE_URL "SC_NARRATIVE_SERVICE_URL"
    45→
    46→/* Simple timestamped log macros */
    47→#define LOG_FMT(ts, lvl, fmt) "[%s] [%s] " fmt "\n", ts, lvl
    48→#define LOG_INF(fmt, ...) log_write("INFO",  fmt, ##__VA_ARGS__)
    49→#define LOG_WRN(fmt, ...) log_write("WARN",  fmt, ##__VA_ARGS__)
    50→#define LOG_ERR(fmt, ...) log_write("ERROR", fmt, ##__VA_ARGS__)
    51→
    52→/* -------------------------------------------------------------------------
    53→ * Data Structures
    54→ * ------------------------------------------------------------------------- */
    55→typedef struct
    56→{
    57→    char    *mem;
    58→    size_t   len;
    59→} response_buf_t;
    60→
    61→struct sc_service_client
    62→{
    63→    /* Service base URLs */
    64→    char *palette_url;
    65→    char *texture_url;
    66→    char *audio_url;
    67→    char *narrative_url;
    68→
    69→    /* Request configuration */
    70→    long  timeout_ms;
    71→    int   max_retries;
    72→    long  backoff_initial_ms;
    73→    double backoff_factor;
    74→
    75→    /* Metrics */
    76→    atomic_ullong requests_total;
    77→    atomic_ullong failures_total;
    78→
    79→    /* libcurl shared handle */
    80→    CURL *curl_handle;
    81→    pthread_mutex_t curl_mtx;
    82→};
    83→
    84→/* -------------------------------------------------------------------------
    85→ * Forward Declarations
    86→ * ------------------------------------------------------------------------- */
    87→static void        log_write(const char *level, const char *fmt, ...);
    88→static size_t      curl_write_cb(void *contents, size_t size, size_t nmemb, void *userp);
    89→static int         perform_request(sc_service_client_t     *client,
    90→                                   const char              *url,
    91→                                   const char              *method,
    92→                                   const char              *json_body,
    93→                                   long                    *http_status,
    94→                                   cJSON                  **out_body);
    95→
    96→static char       *build_full_url(sc_service_endp_t ep, sc_service_client_t *client, const char *path);
    97→
    98→/* -------------------------------------------------------------------------
    99→ * Public API
   100→ * ------------------------------------------------------------------------- */
   101→
   102→sc_service_client_t *sc_service_client_new(void)
   103→{
   104→    sc_service_client_t *cli = calloc(1, sizeof(*cli));
   105→    if (!cli)
   106→    {
   107→        LOG_ERR("Out of memory while allocating service client");
   108→        return NULL;
   109→    }
   110→
   111→    cli->palette_url   = getenv(SC_ENV_PALETTE_URL)   ? strdup(getenv(SC_ENV_PALETTE_URL))   : NULL;
   112→    cli->texture_url   = getenv(SC_ENV_TEXTURE_URL)   ? strdup(getenv(SC_ENV_TEXTURE_URL))   : NULL;
   113→    cli->audio_url     = getenv(SC_ENV_AUDIO_URL)     ? strdup(getenv(SC_ENV_AUDIO_URL))     : NULL;
   114→    cli->narrative_url = getenv(SC_ENV_NARRATIVE_URL) ? strdup(getenv(SC_ENV_NARRATIVE_URL)) : NULL;
   115→
   116→    cli->timeout_ms        = SC_DEFAULT_TIMEOUT_MS;
   117→    cli->max_retries       = SC_DEFAULT_RETRIES;
   118→    cli->backoff_initial_ms = SC_DEFAULT_BACKOFF_MS;
   119→    cli->backoff_factor     = SC_BACKOFF_FACTOR;
   120→
   121→    atomic_init(&cli->requests_total, 0);
   122→    atomic_init(&cli->failures_total, 0);
   123→
   124→    if (pthread_mutex_init(&cli->curl_mtx, NULL) != 0)
   125→    {
   126→        LOG_ERR("Failed to init mutex: %s", strerror(errno));
   127→        free(cli);
   128→        return NULL;
   129→    }
   130→
   131→    if (curl_global_init(CURL_GLOBAL_ALL) != CURLE_OK)
   132→    {
   133→        LOG_ERR("Failed to init libcurl");
   134→        pthread_mutex_destroy(&cli->curl_mtx);
   135→        free(cli);
   136→        return NULL;
   137→    }
   138→
   139→    cli->curl_handle = curl_easy_init();
   140→    if (!cli->curl_handle)
   141→    {
   142→        LOG_ERR("curl_easy_init() failed");
   143→        curl_global_cleanup();
   144→        pthread_mutex_destroy(&cli->curl_mtx);
   145→        free(cli);
   146→        return NULL;
   147→    }
   148→
   149→    /* Use connection pooling */
   150→    curl_easy_setopt(cli->curl_handle, CURLOPT_DNS_CACHE_TIMEOUT, 60L);
   151→
   152→    LOG_INF("Service client initialised");
   153→    return cli;
   154→}
   155→
   156→void sc_service_client_free(sc_service_client_t *cli)
   157→{
   158→    if (!cli) return;
   159→
   160→    LOG_INF("Releasing service client (totalRequests=%" PRIu64 ", failures=%" PRIu64 ")",
   161→            atomic_load(&cli->requests_total), atomic_load(&cli->failures_total));
   162→
   163→    free(cli->palette_url);
   164→    free(cli->texture_url);
   165→    free(cli->audio_url);
   166→    free(cli->narrative_url);
   167→
   168→    if (cli->curl_handle) curl_easy_cleanup(cli->curl_handle);
   169→    curl_global_cleanup();
   170→    pthread_mutex_destroy(&cli->curl_mtx);
   171→    free(cli);
   172→}
   173→
   174→int sc_service_client_call(sc_service_client_t *cli,
   175→                           sc_service_endp_t    endpoint,
   176→                           const char          *method,
   177→                           const char          *path,
   178→                           const char          *request_json,
   179→                           cJSON              **response_json,
   180→                           long                *http_status)
   181→{
   182→    if (!cli || !method || !path || !http_status)
   183→        return SC_EINVAL;
   184→
   185→    char *full_url = build_full_url(endpoint, cli, path);
   186→    if (!full_url)
   187→        return SC_EINVAL;
   188→
   189→    atomic_fetch_add_explicit(&cli->requests_total, 1, memory_order_relaxed);
   190→
   191→    int rc = perform_request(cli, full_url, method, request_json, http_status, response_json);
   192→    free(full_url);
   193→
   194→    if (rc != SC_OK)
   195→        atomic_fetch_add_explicit(&cli->failures_total, 1, memory_order_relaxed);
   196→
   197→    return rc;
   198→}
   199→
   200→/* -------------------------------------------------------------------------
   201→ * Private Implementation
   202→ * ------------------------------------------------------------------------- */
   203→
   204→static char *build_full_url(sc_service_endp_t ep, sc_service_client_t *client, const char *path)
   205→{
   206→    const char *base = NULL;
   207→    switch (ep)
   208→    {
   209→        case SC_EP_PALETTE:   base = client->palette_url;   break;
   210→        case SC_EP_TEXTURE:   base = client->texture_url;   break;
   211→        case SC_EP_AUDIO:     base = client->audio_url;     break;
   212→        case SC_EP_NARRATIVE: base = client->narrative_url; break;
   213→        default: return NULL;
   214→    }
   215→
   216→    if (!base)
   217→    {
   218→        LOG_ERR("Endpoint base URL not configured");
   219→        return NULL;
   220→    }
   221→
   222→    size_t needed = strlen(base) + strlen(path) + 2; /* '/' + '\0' */
   223→    char *url = malloc(needed);
   224→    if (!url) return NULL;
   225→
   226→    snprintf(url, needed, "%s%s%s", base, (path[0] == '/' ? "" : "/"), path);
   227→    return url;
   228→}
   229→
   230→static size_t curl_write_cb(void *contents, size_t size, size_t nmemb, void *userp)
   231→{
   232→    size_t realsize = size * nmemb;
   233→    response_buf_t *mem = (response_buf_t *)userp;
   234→
   235→    char *ptr = realloc(mem->mem, mem->len + realsize + 1);
   236→    if (!ptr)
   237→        return 0; /* will cause CURLE_WRITE_ERROR */
   238→
   239→    mem->mem = ptr;
   240→    memcpy(&(mem->mem[mem->len]), contents, realsize);
   241→    mem->len += realsize;
   242→    mem->mem[mem->len] = 0;
   243→
   244→    return realsize;
   245→}
   246→
   247→static int perform_request(sc_service_client_t *client,
   248→                           const char          *url,
   249→                           const char          *method,
   250→                           const char          *json_body,
   251→                           long                *http_status,
   252→                           cJSON              **out_body)
   253→{
   254→    int      attempt = 0;
   255→    CURLcode res     = CURLE_OK;
   256→    long     status  = 0;
   257→    struct timespec ts_sleep = {0};
   258→    double   backoff_ms = client->backoff_initial_ms;
   259→
   260→    do
   261→    {
   262→        response_buf_t resp;
   263→        resp.mem = malloc(1);
   264→        resp.len = 0;
   265→        if (!resp.mem)
   266→            return SC_ENOMEM;
   267→
   268→        pthread_mutex_lock(&client->curl_mtx);
   269→
   270→        CURL *h = client->curl_handle;
   271→        curl_easy_reset(h);
   272→
   273→        struct curl_slist *hdrs = NULL;
   274→        hdrs = curl_slist_append(hdrs, "Content-Type: application/json");
   275→        hdrs = curl_slist_append(hdrs, "Accept: application/json");
   276→
   277→        curl_easy_setopt(h, CURLOPT_URL, url);
   278→        curl_easy_setopt(h, CURLOPT_HTTPHEADER, hdrs);
   279→        curl_easy_setopt(h, CURLOPT_TIMEOUT_MS, client->timeout_ms);
   280→        curl_easy_setopt(h, CURLOPT_WRITEFUNCTION, curl_write_cb);
   281→        curl_easy_setopt(h, CURLOPT_WRITEDATA, (void *)&resp);
   282→        curl_easy_setopt(h, CURLOPT_CUSTOMREQUEST, method);
   283→
   284→        if (json_body && (strcmp(method, "POST") == 0 || strcmp(method, "PUT") == 0 || strcmp(method, "PATCH") == 0))
   285→            curl_easy_setopt(h, CURLOPT_POSTFIELDS, json_body);
   286→
   287→        res = curl_easy_perform(h);
   288→        if (res == CURLE_OK)
   289→            curl_easy_getinfo(h, CURLINFO_RESPONSE_CODE, &status);
   290→
   291→        pthread_mutex_unlock(&client->curl_mtx);
   292→        curl_slist_free_all(hdrs);
   293→
   294→        if (res == CURLE_OK && status >= 200 && status < 500)
   295→        {
   296→            *http_status = status;
   297→
   298→            if (out_body)
   299→            {
   300→                *out_body = cJSON_Parse(resp.mem);
   301→                if (!*out_body)
   302→                {
   303→                    LOG_ERR("JSON parse error: %s", cJSON_GetErrorPtr());
   304→                    free(resp.mem);
   305→                    return SC_EBADJSON;
   306→                }
   307→            }
   308→
   309→            free(resp.mem);
   310→            return SC_OK;
   311→        }
   312→
   313→        /* transient network/server errors (5xx) are retried */
   314→        LOG_WRN("Request attempt %d failed (curlCode=%d, http=%ld) - retrying...", attempt, res, status);
   315→
   316→        free(resp.mem);
   317→
   318→        /* Exponential backoff with +-10% jitter */
   319→        long jitter = (rand() % (int)(backoff_ms / 10.0 + 1));
   320→        ts_sleep.tv_sec  = (long)((backoff_ms + jitter) / 1000);
   321→        ts_sleep.tv_nsec = ((long)(backoff_ms + jitter) % 1000) * 1000000L;
   322→        nanosleep(&ts_sleep, NULL);
   323→        backoff_ms *= client->backoff_factor;
   324→    }
   325→    while (++attempt <= client->max_retries);
   326→
   327→    *http_status = status;
   328→    LOG_ERR("Request permanently failed after %d attempts", attempt);
   329→    return SC_EREQFAIL;
   330→}
   331→
   332→/* -------------------------------------------------------------------------
   333→ * Logging
   334→ * ------------------------------------------------------------------------- */
   335→#include <stdarg.h>
   336→
   337→static void log_write(const char *level, const char *fmt, ...)
   338→{
   339→    time_t     now = time(NULL);
   340→    struct tm  tm_now;
   341→    char       ts[32];
   342→
   343→    localtime_r(&now, &tm_now);
   344→    strftime(ts, sizeof(ts), "%Y-%m-%dT%H:%M:%S%z", &tm_now);
   345→
   346→    fprintf(stderr, "[%s] [%s] ", ts, level);
   347→
   348→    va_list ap;
   349→    va_start(ap, fmt);
   350→    vfprintf(stderr, fmt, ap);
   351→    va_end(ap);
   352→
   353→    fputc('\n', stderr);
   354→}
