[metadata] {"type": "text", "file": {"filePath": "/app/project/api-gateway/src/services/service_client.c", "content": "/*\n * SynestheticCanvas - API Gateway\n * --------------------------------\n * service_client.c\n *\n * A production-grade, thread-safe service client wrapper around libcurl that is\n * responsible for communicating with downstream creative micro-services\n * (palette, texture, audio, narrative).  The client provides:\n *\n *  • Configurable per-service base URLs loaded from environment variables\n *  • Automatic request instrumentation (request / failure counters)\n *  • Exponential-back-off retries with jitter\n *  • JSON parsing (cJSON) and basic validation\n *  • Centralised structured logging\n *\n * Author  : SynestheticCanvas Core Team\n * License : MIT\n */\n\n#include \"service_client.h\"\n\n#include <curl/curl.h>\n#include <errno.h>\n#include <inttypes.h>\n#include <pthread.h>\n#include <signal.h>\n#include <stdatomic.h>\n#include <stdio.h>\n#include <stdlib.h>\n#include <string.h>\n#include <time.h>\n\n/* -------------------------------------------------------------------------\n * Local Macros & Helpers\n * ------------------------------------------------------------------------- */\n#define SC_DEFAULT_TIMEOUT_MS 5000\n#define SC_DEFAULT_RETRIES        3\n#define SC_DEFAULT_BACKOFF_MS   250\n#define SC_BACKOFF_FACTOR       2.0\n\n#define SC_ENV_PALETTE_URL   \"SC_PALETTE_SERVICE_URL\"\n#define SC_ENV_TEXTURE_URL   \"SC_TEXTURE_SERVICE_URL\"\n#define SC_ENV_AUDIO_URL     \"SC_AUDIO_SERVICE_URL\"\n#define SC_ENV_NARRATIVE_URL \"SC_NARRATIVE_SERVICE_URL\"\n\n/* Simple timestamped log macros */\n#define LOG_FMT(ts, lvl, fmt) \"[%s] [%s] \" fmt \"\\n\", ts, lvl\n#define LOG_INF(fmt, ...) log_write(\"INFO\",  fmt, ##__VA_ARGS__)\n#define LOG_WRN(fmt, ...) log_write(\"WARN\",  fmt, ##__VA_ARGS__)\n#define LOG_ERR(fmt, ...) log_write(\"ERROR\", fmt, ##__VA_ARGS__)\n\n/* -------------------------------------------------------------------------\n * Data Structures\n * ------------------------------------------------------------------------- */\ntypedef struct\n{\n    char    *mem;\n    size_t   len;\n} response_buf_t;\n\nstruct sc_service_client\n{\n    /* Service base URLs */\n    char *palette_url;\n    char *texture_url;\n    char *audio_url;\n    char *narrative_url;\n\n    /* Request configuration */\n    long  timeout_ms;\n    int   max_retries;\n    long  backoff_initial_ms;\n    double backoff_factor;\n\n    /* Metrics */\n    atomic_ullong requests_total;\n    atomic_ullong failures_total;\n\n    /* libcurl shared handle */\n    CURL *curl_handle;\n    pthread_mutex_t curl_mtx;\n};\n\n/* -------------------------------------------------------------------------\n * Forward Declarations\n * ------------------------------------------------------------------------- */\nstatic void        log_write(const char *level, const char *fmt, ...);\nstatic size_t      curl_write_cb(void *contents, size_t size, size_t nmemb, void *userp);\nstatic int         perform_request(sc_service_client_t     *client,\n                                   const char              *url,\n                                   const char              *method,\n                                   const char              *json_body,\n                                   long                    *http_status,\n                                   cJSON                  **out_body);\n\nstatic char       *build_full_url(sc_service_endp_t ep, sc_service_client_t *client, const char *path);\n\n/* -------------------------------------------------------------------------\n * Public API\n * ------------------------------------------------------------------------- */\n\nsc_service_client_t *sc_service_client_new(void)\n{\n    sc_service_client_t *cli = calloc(1, sizeof(*cli));\n    if (!cli)\n    {\n        LOG_ERR(\"Out of memory while allocating service client\");\n        return NULL;\n    }\n\n    cli->palette_url   = getenv(SC_ENV_PALETTE_URL)   ? strdup(getenv(SC_ENV_PALETTE_URL))   : NULL;\n    cli->texture_url   = getenv(SC_ENV_TEXTURE_URL)   ? strdup(getenv(SC_ENV_TEXTURE_URL))   : NULL;\n    cli->audio_url     = getenv(SC_ENV_AUDIO_URL)     ? strdup(getenv(SC_ENV_AUDIO_URL))     : NULL;\n    cli->narrative_url = getenv(SC_ENV_NARRATIVE_URL) ? strdup(getenv(SC_ENV_NARRATIVE_URL)) : NULL;\n\n    cli->timeout_ms        = SC_DEFAULT_TIMEOUT_MS;\n    cli->max_retries       = SC_DEFAULT_RETRIES;\n    cli->backoff_initial_ms = SC_DEFAULT_BACKOFF_MS;\n    cli->backoff_factor     = SC_BACKOFF_FACTOR;\n\n    atomic_init(&cli->requests_total, 0);\n    atomic_init(&cli->failures_total, 0);\n\n    if (pthread_mutex_init(&cli->curl_mtx, NULL) != 0)\n    {\n        LOG_ERR(\"Failed to init mutex: %s\", strerror(errno));\n        free(cli);\n        return NULL;\n    }\n\n    if (curl_global_init(CURL_GLOBAL_ALL) != CURLE_OK)\n    {\n        LOG_ERR(\"Failed to init libcurl\");\n        pthread_mutex_destroy(&cli->curl_mtx);\n        free(cli);\n        return NULL;\n    }\n\n    cli->curl_handle = curl_easy_init();\n    if (!cli->curl_handle)\n    {\n        LOG_ERR(\"curl_easy_init() failed\");\n        curl_global_cleanup();\n        pthread_mutex_destroy(&cli->curl_mtx);\n        free(cli);\n        return NULL;\n    }\n\n    /* Use connection pooling */\n    curl_easy_setopt(cli->curl_handle, CURLOPT_DNS_CACHE_TIMEOUT, 60L);\n\n    LOG_INF(\"Service client initialised\");\n    return cli;\n}\n\nvoid sc_service_client_free(sc_service_client_t *cli)\n{\n    if (!cli) return;\n\n    LOG_INF(\"Releasing service client (totalRequests=%\" PRIu64 \", failures=%\" PRIu64 \")\",\n            atomic_load(&cli->requests_total), atomic_load(&cli->failures_total));\n\n    free(cli->palette_url);\n    free(cli->texture_url);\n    free(cli->audio_url);\n    free(cli->narrative_url);\n\n    if (cli->curl_handle) curl_easy_cleanup(cli->curl_handle);\n    curl_global_cleanup();\n    pthread_mutex_destroy(&cli->curl_mtx);\n    free(cli);\n}\n\nint sc_service_client_call(sc_service_client_t *cli,\n                           sc_service_endp_t    endpoint,\n                           const char          *method,\n                           const char          *path,\n                           const char          *request_json,\n                           cJSON              **response_json,\n                           long                *http_status)\n{\n    if (!cli || !method || !path || !http_status)\n        return SC_EINVAL;\n\n    char *full_url = build_full_url(endpoint, cli, path);\n    if (!full_url)\n        return SC_EINVAL;\n\n    atomic_fetch_add_explicit(&cli->requests_total, 1, memory_order_relaxed);\n\n    int rc = perform_request(cli, full_url, method, request_json, http_status, response_json);\n    free(full_url);\n\n    if (rc != SC_OK)\n        atomic_fetch_add_explicit(&cli->failures_total, 1, memory_order_relaxed);\n\n    return rc;\n}\n\n/* -------------------------------------------------------------------------\n * Private Implementation\n * ------------------------------------------------------------------------- */\n\nstatic char *build_full_url(sc_service_endp_t ep, sc_service_client_t *client, const char *path)\n{\n    const char *base = NULL;\n    switch (ep)\n    {\n        case SC_EP_PALETTE:   base = client->palette_url;   break;\n        case SC_EP_TEXTURE:   base = client->texture_url;   break;\n        case SC_EP_AUDIO:     base = client->audio_url;     break;\n        case SC_EP_NARRATIVE: base = client->narrative_url; break;\n        default: return NULL;\n    }\n\n    if (!base)\n    {\n        LOG_ERR(\"Endpoint base URL not configured\");\n        return NULL;\n    }\n\n    size_t needed = strlen(base) + strlen(path) + 2; /* '/' + '\\0' */\n    char *url = malloc(needed);\n    if (!url) return NULL;\n\n    snprintf(url, needed, \"%s%s%s\", base, (path[0] == '/' ? \"\" : \"/\"), path);\n    return url;\n}\n\nstatic size_t curl_write_cb(void *contents, size_t size, size_t nmemb, void *userp)\n{\n    size_t realsize = size * nmemb;\n    response_buf_t *mem = (response_buf_t *)userp;\n\n    char *ptr = realloc(mem->mem, mem->len + realsize + 1);\n    if (!ptr)\n        return 0; /* will cause CURLE_WRITE_ERROR */\n\n    mem->mem = ptr;\n    memcpy(&(mem->mem[mem->len]), contents, realsize);\n    mem->len += realsize;\n    mem->mem[mem->len] = 0;\n\n    return realsize;\n}\n\nstatic int perform_request(sc_service_client_t *client,\n                           const char          *url,\n                           const char          *method,\n                           const char          *json_body,\n                           long                *http_status,\n                           cJSON              **out_body)\n{\n    int      attempt = 0;\n    CURLcode res     = CURLE_OK;\n    long     status  = 0;\n    struct timespec ts_sleep = {0};\n    double   backoff_ms = client->backoff_initial_ms;\n\n    do\n    {\n        response_buf_t resp;\n        resp.mem = malloc(1);\n        resp.len = 0;\n        if (!resp.mem)\n            return SC_ENOMEM;\n\n        pthread_mutex_lock(&client->curl_mtx);\n\n        CURL *h = client->curl_handle;\n        curl_easy_reset(h);\n\n        struct curl_slist *hdrs = NULL;\n        hdrs = curl_slist_append(hdrs, \"Content-Type: application/json\");\n        hdrs = curl_slist_append(hdrs, \"Accept: application/json\");\n\n        curl_easy_setopt(h, CURLOPT_URL, url);\n        curl_easy_setopt(h, CURLOPT_HTTPHEADER, hdrs);\n        curl_easy_setopt(h, CURLOPT_TIMEOUT_MS, client->timeout_ms);\n        curl_easy_setopt(h, CURLOPT_WRITEFUNCTION, curl_write_cb);\n        curl_easy_setopt(h, CURLOPT_WRITEDATA, (void *)&resp);\n        curl_easy_setopt(h, CURLOPT_CUSTOMREQUEST, method);\n\n        if (json_body && (strcmp(method, \"POST\") == 0 || strcmp(method, \"PUT\") == 0 || strcmp(method, \"PATCH\") == 0))\n            curl_easy_setopt(h, CURLOPT_POSTFIELDS, json_body);\n\n        res = curl_easy_perform(h);\n        if (res == CURLE_OK)\n            curl_easy_getinfo(h, CURLINFO_RESPONSE_CODE, &status);\n\n        pthread_mutex_unlock(&client->curl_mtx);\n        curl_slist_free_all(hdrs);\n\n        if (res == CURLE_OK && status >= 200 && status < 500)\n        {\n            *http_status = status;\n\n            if (out_body)\n            {\n                *out_body = cJSON_Parse(resp.mem);\n                if (!*out_body)\n                {\n                    LOG_ERR(\"JSON parse error: %s\", cJSON_GetErrorPtr());\n                    free(resp.mem);\n                    return SC_EBADJSON;\n                }\n            }\n\n            free(resp.mem);\n            return SC_OK;\n        }\n\n        /* transient network/server errors (5xx) are retried */\n        LOG_WRN(\"Request attempt %d failed (curlCode=%d, http=%ld) - retrying...\", attempt, res, status);\n\n        free(resp.mem);\n\n        /* Exponential backoff with +-10% jitter */\n        long jitter = (rand() % (int)(backoff_ms / 10.0 + 1));\n        ts_sleep.tv_sec  = (long)((backoff_ms + jitter) / 1000);\n        ts_sleep.tv_nsec = ((long)(backoff_ms + jitter) % 1000) * 1000000L;\n        nanosleep(&ts_sleep, NULL);\n        backoff_ms *= client->backoff_factor;\n    }\n    while (++attempt <= client->max_retries);\n\n    *http_status = status;\n    LOG_ERR(\"Request permanently failed after %d attempts\", attempt);\n    return SC_EREQFAIL;\n}\n\n/* -------------------------------------------------------------------------\n * Logging\n * ------------------------------------------------------------------------- */\n#include <stdarg.h>\n\nstatic void log_write(const char *level, const char *fmt, ...)\n{\n    time_t     now = time(NULL);\n    struct tm  tm_now;\n    char       ts[32];\n\n    localtime_r(&now, &tm_now);\n    strftime(ts, sizeof(ts), \"%Y-%m-%dT%H:%M:%S%z\", &tm_now);\n\n    fprintf(stderr, \"[%s] [%s] \", ts, level);\n\n    va_list ap;\n    va_start(ap, fmt);\n    vfprintf(stderr, fmt, ap);\n    va_end(ap);\n\n    fputc('\\n', stderr);\n}\n\n/* -------------------------------------------------------------------------\n * End-of-file\n * ------------------------------------------------------------------------- */\n", "numLines": 359, "startLine": 1, "totalLines": 359}}

1→/**
     2→ * SynestheticCanvas/api-gateway/graphql/resolvers.c
     3→ *
     4→ * Production-grade GraphQL resolver implementations for the SynestheticCanvas
     5→ * API-Gateway.  These resolvers act as a thin facade that translates GraphQL
     6→ * requests into downstream REST/JSON calls, enriches them with observability
     7→ * metadata, performs pagination bookkeeping, and returns the materialized
     8→ * JSON back to the GraphQL runtime.
     9→ *
    10→ * © 2024 SynestheticCanvas Contributors
    11→ */
    12→
    13→#include <stdio.h>
    14→#include <stdlib.h>
    15→#include <string.h>
    16→#include <errno.h>
    17→#include <pthread.h>
    18→#include <curl/curl.h>
    19→#include <jansson.h>
    20→
    21→#include "graphql.h"        /* Project-internal GraphQL runtime abstractions */
    22→#include "logging.h"        /* Structured logger (spdlog-like facade)        */
    23→#include "metrics.h"        /* Prometheus metrics facade                     */
    24→#include "rate_limit.h"     /* Leaky-bucket rate limiter                     */
    25→#include "resolvers.h"      /* Header for this implementation                */
    26→
    27→/* -------------------------------------------------------------------------- */
    28→/*                          Compile-time configuration                        */
    29→/* -------------------------------------------------------------------------- */
    30→
    31→#ifndef PALETTE_SERVICE_BASE_URL
    32→#define PALETTE_SERVICE_BASE_URL "http://palette-service.internal:8080/v1"
    33→#endif
    34→
    35→#ifndef HTTP_TIMEOUT_SECS
    36→#define HTTP_TIMEOUT_SECS 3L
    37→#endif
    38→
    39→/* -------------------------------------------------------------------------- */
    40→/*                              Local structures                              */
    41→/* -------------------------------------------------------------------------- */
    42→
    43→/* GraphQL resolver context – passed as `void *user_data` by the runtime.     */
    44→typedef struct gql_context {
    45→    logger_t      *log;
    46→    metrics_t     *metrics;
    47→    rate_limiter_t *limiter;
    48→} gql_context_t;
    49→
    50→
    51→/* libcurl response aggregator */
    52→typedef struct curl_buffer {
    53→    char *data;
    54→    size_t size;
    55→} curl_buffer_t;
    56→
    57→
    58→/* -------------------------------------------------------------------------- */
    59→/*                       HTTP/REST helper implementation                      */
    60→/* -------------------------------------------------------------------------- */
    61→
    62→static size_t curl_buffer_write(void *contents, size_t size, size_t nmemb, void *userp)
    63→{
    64→    size_t realsize    = size * nmemb;
    65→    curl_buffer_t *mem = (curl_buffer_t *)userp;
    66→
    67→    char *ptr = realloc(mem->data, mem->size + realsize + 1);
    68→    if (!ptr) {
    69→        /* Out of memory – abort transfer */
    70→        return 0;
    71→    }
    72→
    73→    mem->data = ptr;
    74→    memcpy(&(mem->data[mem->size]), contents, realsize);
    75→    mem->size += realsize;
    76→    mem->data[mem->size] = '\0';
    77→
    78→    return realsize;
    79→}
    80→
    81→/* Perform an HTTP GET and parse the JSON payload. */
    82→static json_t *http_json_get(const char *url, logger_t *log, GQLError **gql_err)
    83→{
    84→    CURL *curl = curl_easy_init();
    85→    if (!curl) {
    86→        LOG_ERROR(log, "curl_easy_init() failed");
    87→        *gql_err = gql_error_new(GQL_ERR_INTERNAL, "Internal HTTP init error");
    88→        return NULL;
    89→    }
    90→
    91→    curl_buffer_t chunk = {.data = NULL, .size = 0};
    92→
    93→    curl_easy_setopt(curl, CURLOPT_URL, url);
    94→    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, curl_buffer_write);
    95→    curl_easy_setopt(curl, CURLOPT_WRITEDATA, (void *)&chunk);
    96→    curl_easy_setopt(curl, CURLOPT_TIMEOUT, HTTP_TIMEOUT_SECS);
    97→    curl_easy_setopt(curl, CURLOPT_USERAGENT, "SynestheticCanvas-Gateway/1.0");
    98→
    99→    CURLcode res = curl_easy_perform(curl);
   100→    long http_status = 0;
   101→    curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_status);
   102→    curl_easy_cleanup(curl);
   103→
   104→    if (res != CURLE_OK) {
   105→        LOG_ERROR(log, "curl_easy_perform() failed: %s", curl_easy_strerror(res));
   106→        free(chunk.data);
   107→        *gql_err = gql_error_new(GQL_ERR_NETWORK, "Upstream network error");
   108→        return NULL;
   109→    }
   110→
   111→    if (http_status >= 400) {
   112→        LOG_WARN(log, "Upstream error %ld for GET %s", http_status, url);
   113→        free(chunk.data);
   114→
   115→        if (http_status == 404) {
   116→            *gql_err = gql_error_new(GQL_ERR_NOT_FOUND, "Resource not found");
   117→        } else {
   118→            *gql_err = gql_error_new(GQL_ERR_UPSTREAM, "Upstream service error");
   119→        }
   120→        return NULL;
   121→    }
   122→
   123→    /* Parse JSON payload */
   124→    json_error_t json_err;
   125→    json_t *json = json_loads(chunk.data, 0, &json_err);
   126→    free(chunk.data);
   127→
   128→    if (!json) {
   129→        LOG_ERROR(log, "JSON parse error on line %d: %s", json_err.line, json_err.text);
   130→        *gql_err = gql_error_new(GQL_ERR_INTERNAL, "Invalid upstream JSON");
   131→        return NULL;
   132→    }
   133→
   134→    return json;
   135→}
   136→
   137→/* -------------------------------------------------------------------------- */
   138→/*                                Validators                                  */
   139→/* -------------------------------------------------------------------------- */
   140→
   141→/* Validate a UUID argument (simple length/format check). */
   142→static int validate_uuid_arg(const char *uuid, GQLError **gql_err)
   143→{
   144→    /* Very permissive validation; can be swapped for libcork or libuuid */
   145→    if (!uuid || strlen(uuid) != 36) {
   146→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "Invalid UUID");
   147→        return -1;
   148→    }
   149→    return 0;
   150→}
   151→
   152→/* Extract and validate pagination arguments. */
   153→static int extract_pagination(const json_t *args,
   154→                              size_t *out_first,
   155→                              const char **out_after,
   156→                              GQLError **gql_err)
   157→{
   158→    json_t *first_json = json_object_get(args, "first");
   159→    json_t *after_json = json_object_get(args, "after");
   160→
   161→    if (first_json && !json_is_integer(first_json)) {
   162→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "`first` must be an integer");
   163→        return -1;
   164→    }
   165→
   166→    if (after_json && !json_is_string(after_json)) {
   167→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "`after` must be a string cursor");
   168→        return -1;
   169→    }
   170→
   171→    if (first_json) *out_first = (size_t)json_integer_value(first_json);
   172→    if (after_json) *out_after = json_string_value(after_json);
   173→
   174→    return 0;
   175→}
   176→
   177→/* -------------------------------------------------------------------------- */
   178→/*                          Resolver implementations                          */
   179→/* -------------------------------------------------------------------------- */
   180→
   181→/**
   182→ * palette(id: ID!): Palette!
   183→ */
   184→static json_t *resolve_palette(const json_t *args, void *user_data, GQLError **gql_err)
   185→{
   186→    gql_context_t *ctx = (gql_context_t *)user_data;
   187→
   188→    const char *id = json_string_value(json_object_get(args, "id"));
   189→    if (validate_uuid_arg(id, gql_err) < 0) {
   190→        return NULL;
   191→    }
   192→
   193→    /* Throttle upstream calls */
   194→    if (rate_limiter_acquire(ctx->limiter) != 0) {
   195→        *gql_err = gql_error_new(GQL_ERR_RATE_LIMIT, "Too many requests");
   196→        return NULL;
   197→    }
   198→
   199→    char url[512];
   200→    snprintf(url, sizeof(url), "%s/palettes/%s", PALETTE_SERVICE_BASE_URL, id);
   201→
   202→    LOG_INFO(ctx->log, "GET %s", url);
   203→    json_t *payload = http_json_get(url, ctx->log, gql_err);
   204→    if (!payload) {
   205→        return NULL;
   206→    }
   207→
   208→    METRIC_INC(ctx->metrics, "palette_resolver_success");
   209→    return payload; /* Ownership transferred to GraphQL runtime */
   210→}
   211→
   212→/**
   213→ * palettes(first: Int, after: String): PaletteConnection!
   214→ */
   215→static json_t *resolve_palettes(const json_t *args, void *user_data, GQLError **gql_err)
   216→{
   217→    gql_context_t *ctx = (gql_context_t *)user_data;
   218→
   219→    size_t first       = 25; /* default page size */
   220→    const char *after  = NULL;
   221→
   222→    if (extract_pagination(args, &first, &after, gql_err) < 0) {
   223→        return NULL;
   224→    }
   225→
   226→    if (first == 0 || first > 100) {
   227→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "`first` must be between 1 and 100");
   228→        return NULL;
   229→    }
   230→
   231→    /* Construct query string */
   232→    char url[512];
   233→    if (after) {
   234→        snprintf(url, sizeof(url),
   235→                 "%s/palettes?limit=%zu&cursor=%s", PALETTE_SERVICE_BASE_URL, first, after);
   236→    } else {
   237→        snprintf(url, sizeof(url),
   238→                 "%s/palettes?limit=%zu", PALETTE_SERVICE_BASE_URL, first);
   239→    }
   240→
   241→    LOG_INFO(ctx->log, "GET %s", url);
   242→    json_t *payload = http_json_get(url, ctx->log, gql_err);
   243→    if (!payload) {
   244→        return NULL;
   245→    }
   246→
   247→    METRIC_INC(ctx->metrics, "palettes_resolver_success");
   248→    return payload;
   249→}
