   251→/**
   252→ * createPalette(input: CreatePaletteInput!): Palette!
   253→ *
   254→ * For simplicity, we forward the entire JSON payload to the palette service.
   255→ */
   256→static json_t *resolve_create_palette(const json_t *args, void *user_data, GQLError **gql_err)
   257→{
   258→    gql_context_t *ctx = (gql_context_t *)user_data;
   259→
   260→    /* Rate limiting */
   261→    if (rate_limiter_acquire(ctx->limiter) != 0) {
   262→        *gql_err = gql_error_new(GQL_ERR_RATE_LIMIT, "Too many requests");
   263→        return NULL;
   264→    }
   265→
   266→    /* Validate mandatory fields */
   267→    const json_t *input = json_object_get(args, "input");
   268→    if (!input || !json_is_object(input)) {
   269→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "`input` must be provided");
   270→        return NULL;
   271→    }
   272→
   273→    const char *name = json_string_value(json_object_get(input, "name"));
   274→    if (!name || strlen(name) == 0) {
   275→        *gql_err = gql_error_new(GQL_ERR_VALIDATION, "`name` cannot be empty");
   276→        return NULL;
   277→    }
   278→
   279→    /* Serialize input to JSON for POST body */
   280→    char *body = json_dumps(input, JSON_COMPACT);
