   290→        *gql_err = gql_error_new(GQL_ERR_INTERNAL, "Internal HTTP init error");
   291→        return NULL;
   292→    }
   293→
   294→    char url[512];
   295→    snprintf(url, sizeof(url), "%s/palettes", PALETTE_SERVICE_BASE_URL);
