   199→/* Generates a binary PGM buffer (always 8-bit grayscale). */
   200→static int generate_texture_pgm(unsigned width,
   201→                                unsigned height,
   202→                                float     scale,
   203→                                unsigned char **out_buf,
   204→                                size_t    *out_size)
   205→{
   206→    if (!out_buf || !out_size)
   207→        return -1;
   208→
   209→    const size_t header_len = 32;
   210→    const size_t img_len    = width * height;
   211→    size_t total_len        = header_len + img_len;
   212→
   213→    unsigned char *buf = malloc(total_len);
   214→    if (!buf)
   215→        return -1;
   216→
   217→    int header_written = snprintf((char*)buf, header_len, "P5\n%u %u\n255\n", width, height);
   218→    if (header_written < 0 || (size_t)header_written >= header_len) {
   219→        free(buf);
   220→        return -1;
   221→    }
   222→
   223→    unsigned char *pixels = buf + header_written;
   224→    float inv_scale       = 1.0f / (scale <= 0.0f ? DEFAULT_SCALE : scale);
   225→
   226→    for (unsigned y = 0; y < height; ++y) {
   227→        for (unsigned x = 0; x < width; ++x) {
   228→            float nx = x * inv_scale;
   229→            float ny = y * inv_scale;
   230→            float v  = fbm(nx, ny, 5, 2.0f, 0.5f); /* 5 octave FBM */
   231→            /* Normalize */
   232→            v = fminf(fmaxf(v, 0.0f), 1.0f);
   233→            pixels[y*width + x] = (unsigned char)(v * 255.0f);
   234→        }
   235→    }
   236→
   237→    *out_buf  = buf;
   238→    *out_size = header_written + img_len;
   239→    return 0;
   240→}
