   242→/* ---------- HTTP Request Handling --------------------------------------- */
   243→
   244→typedef struct {
   245→    struct MHD_Daemon *daemon;
   246→    ServiceConfig      cfg;
   247→} ServiceCtx;
   248→
   249→static enum MHD_Result
   250→send_response(struct MHD_Connection *conn,
   251→              const char           *mime,
   252→              const unsigned char  *data,
   253→              size_t                size,
   254→              unsigned int          status)
   255→{
   256→    struct MHD_Response *resp = MHD_create_response_from_buffer(size,
