   268→/* Helpers to parse int params safely */
   269→static int query_param_int(struct MHD_Connection *conn,
   270→                           const char *key,
   271→                           int def,
   272→                           int *out_val)
   273→{
   274→    const char *str = MHD_lookup_connection_value(conn, MHD_GET_ARGUMENT_KIND, key);
   275→    if (!str) {
