   289→static int handle_healthz(struct MHD_Connection *conn)
   290→{
   291→    const char *ok = "{\"status\":\"ok\"}";
   292→    return send_response(conn, "application/json", (const unsigned char*)ok,
   293→                         strlen(ok), MHD_HTTP_OK);
   294→}
   295→
   296→static int handle_noise(ServiceCtx          *svc,
   297→                        struct MHD_Connection *conn)
   298→{
   299→    int width, height;
   300→    if (query_param_int(conn, "width", 256, &width)   ||
   301→        query_param_int(conn, "height", 256, &height))
   302→    {
   303→        const char *err = "{\"error\":\"invalid width/height\"}";
   304→        return send_response(conn, "application/json",
   305→                             (const unsigned char*)err,
   306→                             strlen(err),
   307→                             MHD_HTTP_BAD_REQUEST);
   308→    }
   309→
   310→    if (width  <= 0 || width  > (int)svc->cfg.max_texture_size ||
   311→        height <= 0 || height > (int)svc->cfg.max_texture_size)
   312→    {
   313→        const char *err = "{\"error\":\"dimensions out of range\"}";
   314→        return send_response(conn, "application/json",
   315→                             (const unsigned char*)err,
   316→                             strlen(err),
   317→                             MHD_HTTP_BAD_REQUEST);
   318→    }
   319→
   320→    float scale = DEFAULT_SCALE;
   321→    const char *scale_str = MHD_lookup_connection_value(conn,
   322→                                MHD_GET_ARGUMENT_KIND, "scale");
   323→    if (scale_str)
   324→        scale = strtof(scale_str, NULL);
   325→
   326→    unsigned char *buf  = NULL;
   327→    size_t         size = 0;
   328→    if (generate_texture_pgm((unsigned)width,
   329→                             (unsigned)height,
   330→                             scale,
   331→                             &buf,
   332→                             &size) != 0)
   333→    {
   334→        const char *err = "{\"error\":\"generation failed\"}";
   335→        return send_response(conn, "application/json",
   336→                             (const unsigned char*)err,
   337→                             strlen(err),
   338→                             MHD_HTTP_INTERNAL_SERVER_ERROR);
   339→    }
   340→
   341→    enum MHD_Result res = send_response(conn, "image/x-pgm", buf, size,
   342→                                        MHD_HTTP_OK);
   343→    free(buf);
   344→    return res;
   345→}
