   347→/* libmicrohttpd callback */
   348→static enum MHD_Result
   349→request_router(void                *cls,
   350→               struct MHD_Connection *connection,
   351→               const char           *url,
   352→               const char           *method,
   353→               const char           *version,
   354→               const char           *upload_data,
   355→               size_t               *upload_data_size,
   356→               void                **con_cls)
   357→{
   358→    (void)cls; (void)version; (void)upload_data; (void)upload_data_size; (void)con_cls;
   359→
   360→    if (strcmp(method, "GET") != 0)
   361→        return MHD_NO;
   362→
   363→    ServiceCtx *svc = (ServiceCtx*)cls;
   364→
   365→    if (strcmp(url, "/healthz") == 0) {
   366→        return handle_healthz(connection);
   367→    }
   368→    else if (strcmp(url, "/v1/noise") == 0) {
   369→        return handle_noise(svc, connection);
   370→    }
   371→    else {
   372→        const char *err = "{\"error\":\"not found\"}";
   373→        return send_response(connection, "application/json",
   374→                             (const unsigned char*)err,
   375→                             strlen(err),
   376→                             MHD_HTTP_NOT_FOUND);
   377→    }
   378→}
