   380→/* ---------- Graceful Shutdown ------------------------------------------- */
   381→
   382→static volatile sig_atomic_t g_shutdown = 0;
   383→
   384→static void on_signal(int sig)
   385→{
   386→    (void)sig;
   387→    g_shutdown = 1;
   388→}
   389→
   390→/* ---------- Main -------------------------------------------------------- */
   391→
   392→int main(void)
   393→{
   394→    ServiceCtx svc;
   395→    config_set_defaults(&svc.cfg);
   396→
   397→    /* --- Load configuration file if provided -------------------------- */
   398→    const char *cfg_path = getenv(CONFIG_ENV_VAR);
   399→    if (cfg_path && *cfg_path) {
   400→        if (config_from_file(cfg_path, &svc.cfg) != 0) {
   401→            log_msg(LOG_WARN, "Falling back to default config (%s)", strerror(errno));
   402→        }
   403→    }
   404→    g_log_level = svc.cfg.log_level;
   405→
   406→    log_msg(LOG_INFO, "Texture-Service starting on port %u", svc.cfg.port);
   407→
   408→    /* --- Setup signal handlers ---------------------------------------- */
   409→    struct sigaction sa;
   410→    memset(&sa, 0, sizeof(sa));
   411→    sa.sa_handler = on_signal;
   412→    sigaction(SIGINT,  &sa, NULL);
   413→    sigaction(SIGTERM, &sa, NULL);
   414→
   415→    /* --- Start HTTP daemon -------------------------------------------- */
   416→    svc.daemon = MHD_start_daemon(MHD_USE_AUTO | MHD_USE_INTERNAL_POLLING_THREAD,
   417→                                  svc.cfg.port,
   418→                                  NULL, NULL,
   419→                                  request_router, &svc,
   420→                                  MHD_OPTION_CONNECTION_TIMEOUT, (unsigned int)10,
   421→                                  MHD_OPTION_END);
   422→    if (!svc.daemon) {
   423→        log_msg(LOG_FATAL, "Failed to start HTTP daemon");
   424→    }
   425→
   426→    log_msg(LOG_INFO, "Texture-Service ready (max_texture_size=%u)",
   427→            svc.cfg.max_texture_size);
   428→
   429→    /* --- Wait until a termination signal is received ------------------ */
   430→    while (!g_shutdown)
   431→        sleep(1);
   432→
   433→    log_msg(LOG_INFO, "Shutting down...");
   434→    MHD_stop_daemon(svc.daemon);
   435→
   436→    log_msg(LOG_INFO, "Shutdown complete");
   437→    return EXIT_SUCCESS;
   438→}

