     4→ * texture_handler.c
     5→ *
     6→ * Production-grade implementation of the TextureHandler API.  The handler
     7→ * validates incoming texture requests, coordinates with the repository layer,
     8→ * updates runtime metrics, and emits structured logs.  All public functions
     9→ * are thread-safe and resilient to partial failures.
    10→ *
    11→ * NOTE: This compilation unit purposefully hides private implementation
    12→ * details from the header, keeping the public surface minimal and stable.
    13→ *
    14→ * Dependencies (resolved through include-paths / pkg-config):
    15→ *   - jansson          (JSON parsing / serialization)
    16→ *   - pthread          (POSIX threading primitives)
    17→ *   - uuid             (libuuid for unique IDs)
    18→ *
    19→ * Author: SynestheticCanvas Core Team
    20→ * License: MIT
    21→ */
    22→
    23→#include <assert.h>
    24→#include <errno.h>
    25→#include <limits.h>
    26→#include <pthread.h>
    27→#include <stdbool.h>
    28→#include <stdio.h>
    29→#include <stdlib.h>
    30→#include <string.h>
    31→#include <uuid/uuid.h>
    32→
    33→#include <jansson.h>
    34→
    35→#include "logger.h"              /* Project-local, syslog-backed logging wrapper */
    36→#include "metrics.h"             /* Histogram / Counter helpers */
    37→#include "texture_handler.h"     /* Corresponding public header */
    38→#include "texture_repository.h"  /* Repository Pattern abstraction */
    39→#include "validation.h"          /* Utility validators for inbound DTOs */
    40→
    41→/* ────────────────────────────────────────────────────────────────────────── */
    42→/* Internal Constants                                                       */
    43→/* ────────────────────────────────────────────────────────────────────────── */
    44→
    45→#define TEXTURE_ID_STRLEN 37           /* 36 bytes UUID + NUL */
    46→#define MAX_TEXTURE_NAME_LEN 128
    47→#define MAX_COLOR_PROFILE_LEN 32
    48→#define JSON_SERIALIZATION_FLAGS (JSON_COMPACT | JSON_SORT_KEYS)
    49→
    50→/* ────────────────────────────────────────────────────────────────────────── */
    51→/* Private Helper Structs / Types                                           */
    52→/* ────────────────────────────────────────────────────────────────────────── */
    53→
    54→/* Guard state for thread-safe handler */
    55→typedef struct
    56→{
    57→    TextureRepository *repo;       /* Injected storage adapter (non-null) */
    58→    MetricsCollector  *metrics;    /* Global metrics sink (may be null)   */
    59→    pthread_rwlock_t   lock;       /* Protects repository multi-step ops  */
    60→    bool               ready;      /* Handler has been initialized        */
    61→} TextureHandlerState;
    62→
    63→/* Encoded error detail used for internal propagation */
    64→typedef struct
    65→{
    66→    TextureErrorCode code;
    67→    char             msg[256];
    68→} TextureErrorDetail;
    69→
    70→/* ────────────────────────────────────────────────────────────────────────── */
    71→/* Local Forward Declarations                                               */
    72→/* ────────────────────────────────────────────────────────────────────────── */
    73→
    74→static void        _set_error(TextureError *out, TextureErrorCode code, const char *fmt, ...)
    75→    __attribute__((format(printf, 3, 4)));
    76→static bool        _validate_texture_input(const TextureInput *in, TextureError *err);
    77→static char       *_generate_uuid(void);
    78→static json_t     *_texture_to_json(const Texture *tx, TextureError *err);
    79→
    80→/* ────────────────────────────────────────────────────────────────────────── */
    81→/* Public API Implementation                                                */
    82→/* ────────────────────────────────────────────────────────────────────────── */
    83→
    84→TextureHandler *texture_handler_new(TextureRepository *repo, MetricsCollector *metrics, TextureError *err)
    85→{
    86→    if (repo == NULL)
    87→    {
    88→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "TextureRepository instance cannot be NULL");
    89→        return NULL;
    90→    }
    91→
    92→    TextureHandlerState *state = calloc(1, sizeof(TextureHandlerState));
    93→    if (!state)
    94→    {
    95→        _set_error(err, TX_ERR_OOM, "Failed to allocate handler state: %s", strerror(errno));
    96→        return NULL;
    97→    }
    98→
    99→    state->repo    = repo;
   100→    state->metrics = metrics;
   101→    state->ready   = false;
   102→
   103→    if (pthread_rwlock_init(&state->lock, NULL) != 0)
   104→    {
   105→        _set_error(err, TX_ERR_INTERNAL, "Failed to initialize rwlock: %s", strerror(errno));
   106→        free(state);
   107→        return NULL;
   108→    }
   109→
   110→    state->ready = true;
   111→    log_info("[texture-handler] Initialized successfully");
   112→
   113→    return (TextureHandler *)state;
   114→}
   115→
   116→void texture_handler_dispose(TextureHandler *handler)
   117→{
   118→    if (!handler)
   119→        return;
   120→
   121→    TextureHandlerState *state = (TextureHandlerState *)handler;
   122→    pthread_rwlock_destroy(&state->lock);
   123→    /* Repository and metrics lifetime are managed by the caller */
   124→    free(state);
   125→}
   126→
   127→/**
   128→ * Create a new texture based on the DTO provided by higher layers. This
   129→ * function validates all fields, generates an ID, persists the record, and
   130→ * returns a deep-copied Texture object that the caller must free.
   131→ */
   132→Texture *texture_handler_create(TextureHandler *handler,
   133→                                const TextureInput *input,
   134→                                TextureError *err)
   135→{
   136→    TextureHandlerState *state = (TextureHandlerState *)handler;
   137→    if (!state || !state->ready)
   138→    {
   139→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   140→        return NULL;
   141→    }
   142→
   143→    /* Validate input first */
   144→    if (!_validate_texture_input(input, err))
   145→        return NULL;
   146→
   147→    /* Build Texture domain object */
   148→    Texture tx      = {0};
   149→    tx.id           = _generate_uuid();
   150→    tx.name         = strndup(input->name, MAX_TEXTURE_NAME_LEN);
   151→    tx.color_profile= strndup(input->color_profile, MAX_COLOR_PROFILE_LEN);
   152→    tx.width        = input->width;
   153→    tx.height       = input->height;
   154→    tx.created_at   = (uint64_t)time(NULL);
   155→
   156→    if (!tx.id || !tx.name || !tx.color_profile)
   157→    {
   158→        _set_error(err, TX_ERR_OOM, "Failed to allocate texture attributes");
   159→        goto cleanup_fail;
   160→    }
   161→
   162→    /* Serialize metadata payload */
   163→    tx.metadata = _texture_to_json(&tx, err);
   164→    if (!tx.metadata)
   165→        goto cleanup_fail;
   166→
   167→    /* Acquire write-lock for repository update */
   168→    if (pthread_rwlock_wrlock(&state->lock) != 0)
   169→    {
   170→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire write lock");
   171→        goto cleanup_fail;
   172→    }
   173→
   174→    bool persist_ok = repository_save_texture(state->repo, &tx, err);
   175→    pthread_rwlock_unlock(&state->lock);
   176→
   177→    if (!persist_ok)
   178→        goto cleanup_fail;
   179→
   180→    /* Metrics */
   181→    if (state->metrics)
   182→        metrics_counter_inc(state->metrics, "texture_created_total", 1);
   183→
   184→    /* Deep copy result for caller (repository may own original memory) */
   185→    Texture *result = texture_clone(&tx, err);
   186→    texture_free(&tx); /* Free local copy */
   187→
   188→    log_info("[texture-handler] Created texture '%s' (%ux%u)", result->id, result->width, result->height);
   189→    return result;
   190→
   191→cleanup_fail:
   192→    texture_free(&tx);
   193→    return NULL;
   194→}
   195→
   196→/**
   197→ * Retrieve a single texture by its UUID. Caller is responsible for freeing
   198→ * the returned object via texture_free().
   199→ */
   200→Texture *texture_handler_get(TextureHandler *handler, const char *texture_id, TextureError *err)
   201→{
   202→    TextureHandlerState *state = (TextureHandlerState *)handler;
   203→    if (!state || !state->ready)
   204→    {
   205→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   206→        return NULL;
   207→    }
   208→
   209→    if (!validation_is_uuid(texture_id))
   210→    {
   211→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "Invalid UUID provided: '%s'", texture_id);
   212→        return NULL;
   213→    }
   214→
   215→    if (pthread_rwlock_rdlock(&state->lock) != 0)
   216→    {
   217→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire read lock");
   218→        return NULL;
   219→    }
   220→
   221→    Texture *tx = repository_get_texture(state->repo, texture_id, err);
   222→    pthread_rwlock_unlock(&state->lock);
   223→
   224→    if (!tx)
   225→        return NULL; /* Error already populated */
   226→
   227→    if (state->metrics)
   228→        metrics_counter_inc(state->metrics, "texture_fetched_total", 1);
   229→
   230→    return tx; /* Ownership transferred to caller */
   231→}
   232→
   233→/**
   234→ * Paginated list of textures.  Returns the number of items copied into
   235→ * out_list, or SIZE_MAX on error.
   236→ *
   237→ * The out_list vector is allocated by the caller; this function fills it up to
   238→ * page_req->page_size. Each populated entry must be released with
   239→ * texture_free() by the caller.
   240→ */
   241→size_t texture_handler_list(TextureHandler           *handler,
   242→                            const PaginationRequest  *page_req,
   243→                            Texture                 **out_list,
   244→                            TextureError             *err)
   245→{
   246→    memset(out_list, 0, sizeof(Texture *) * page_req->page_size);
   247→
   248→    TextureHandlerState *state = (TextureHandlerState *)handler;
   249→    if (!state || !state->ready)
   250→    {
   251→        _set_error(err, TX_ERR_NOT_INITIALIZED, "TextureHandler is not initialized");
   252→        return SIZE_MAX;
   253→    }
   254→
   255→    if (!page_req || !validation_is_pagination_request_valid(page_req))
   256→    {
   257→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "Invalid pagination request");
   258→        return SIZE_MAX;
   259→    }
   260→
   261→    if (pthread_rwlock_rdlock(&state->lock) != 0)
   262→    {
   263→        _set_error(err, TX_ERR_INTERNAL, "Failed to acquire read lock");
   264→        return SIZE_MAX;
   265→    }
   266→
   267→    size_t fetched = repository_list_textures(state->repo, page_req, out_list, err);
   268→    pthread_rwlock_unlock(&state->lock);
   269→
   270→    if (fetched == SIZE_MAX)
   271→        return SIZE_MAX;
   272→
   273→    if (state->metrics)
   274→        metrics_histogram_observe(state->metrics, "textures_per_page", fetched);
   275→
   276→    log_debug("[texture-handler] Listed %zu textures (page %u)", fetched, page_req->page_index);
   277→    return fetched;
   278→}
