   314→/* ────────────────────────────────────────────────────────────────────────── */
   315→/* Private Helpers                                                          */
   316→/* ────────────────────────────────────────────────────────────────────────── */
   317→
   318→static void _set_error(TextureError *out, TextureErrorCode code, const char *fmt, ...)
   319→{
   320→    if (!out)
   321→        return;
   322→
   323→    va_list ap;
   324→    va_start(ap, fmt);
   325→    vsnprintf(out->message, sizeof(out->message), fmt, ap);
   326→    va_end(ap);
   327→
   328→    out->code = code;
   329→}
   330→
   331→static bool _validate_texture_input(const TextureInput *in, TextureError *err)
   332→{
   333→    if (!in)
   334→    {
   335→        _set_error(err, TX_ERR_INVALID_ARGUMENT, "TextureInput cannot be NULL");
   336→        return false;
   337→    }
   338→
   339→    if (!validation_is_valid_name(in->name, MAX_TEXTURE_NAME_LEN))
   340→    {
   341→        _set_error(err, TX_ERR_VALIDATION, "Invalid texture name");
   342→        return false;
   343→    }
   344→
   345→    if (!validation_is_color_profile(in->color_profile))
   346→    {
   347→        _set_error(err, TX_ERR_VALIDATION, "Unsupported color profile '%s'", in->color_profile);
   348→        return false;
   349→    }
   350→
   351→    if (in->width == 0 || in->height == 0 || in->width > 16384 || in->height > 16384)
   352→    {
   353→        _set_error(err, TX_ERR_VALIDATION, "Texture dimensions out of bounds (1..16384)");
   354→        return false;
   355→    }
   356→
   357→    return true;
   358→}
   359→
   360→static char *_generate_uuid(void)
   361→{
   362→    uuid_t bin;
   363→    uuid_generate_random(bin);
   364→
   365→    char *str = malloc(TEXTURE_ID_STRLEN);
   366→    if (!str)
   367→        return NULL;
   368→
   369→    uuid_unparse_lower(bin, str);
   370→    return str;
   371→}
   372→
   373→static json_t *_texture_to_json(const Texture *tx, TextureError *err)
   374→{
   375→    json_t *obj = json_object();
   376→    if (!obj)
   377→    {
   378→        _set_error(err, TX_ERR_OOM, "Failed to allocate JSON object");
   379→        return NULL;
   380→    }
   381→
   382→    if (json_object_set_new(obj, "id",            json_string(tx->id))           < 0 ||
   383→        json_object_set_new(obj, "name",          json_string(tx->name))         < 0 ||
   384→        json_object_set_new(obj, "color_profile", json_string(tx->color_profile))< 0 ||
   385→        json_object_set_new(obj, "width",         json_integer(tx->width))       < 0 ||
   386→        json_object_set_new(obj, "height",        json_integer(tx->height))      < 0 ||
   387→        json_object_set_new(obj, "created_at",    json_integer(tx->created_at))  < 0)
   388→    {
   389→        json_decref(obj);
   390→        _set_error(err, TX_ERR_INTERNAL, "Failed to build texture JSON payload");
   391→        return NULL;
   392→    }
   393→
   394→    return obj;
   395→}
