    46→/* -------------------------------------------------------------------------- */
    47→/*                              Logging helpers                               */
    48→/* -------------------------------------------------------------------------- */
    49→static int CURRENT_LOG_LEVEL = LOG_INFO;
    50→
    51→#define LOG(level, fmt, ...)                     \
    52→    do {                                         \
    53→        if ((level) <= CURRENT_LOG_LEVEL) {      \
    54→            syslog(level, fmt, ##__VA_ARGS__);   \
    55→        }                                        \
    56→    } while (0)
    57→
    58→#define LOG_DEBUG(fmt, ...)  LOG(LOG_DEBUG,  fmt, ##__VA_ARGS__)
    59→#define LOG_INFO_(fmt, ...)  LOG(LOG_INFO,   fmt, ##__VA_ARGS__)
    60→#define LOG_WARN(fmt, ...)   LOG(LOG_WARNING,fmt, ##__VA_ARGS__)
    61→#define LOG_ERR_(fmt, ...)   LOG(LOG_ERR,    fmt, ##__VA_ARGS__)
    62→
    63→/* -------------------------------------------------------------------------- */
    64→/*                               Data models                                  */
    65→/* -------------------------------------------------------------------------- */
    66→#define UUID_LEN        36u
    67→#define MAX_NAME_LEN   127u
    68→#define MAX_COLORS       8u   /* maximum colours within a palette           */
    69→#define MAX_PALETTES  4096u   /* in-memory cap (fits most demo/show-cases)  */
    70→
    71→typedef struct {
    72→    char     id[UUID_LEN + 1];
    73→    char     name[MAX_NAME_LEN + 1];
    74→    char     colors[MAX_COLORS][8];     /* hex colours “#RRGGBB”              */
    75→    size_t   color_count;
    76→    time_t   created_at;
    77→} Palette;
    78→
    79→typedef struct {
    80→    Palette           *palettes[MAX_PALETTES];
    81→    size_t             count;
    82→    pthread_mutex_t    lock;
    83→} PaletteRepository;
    84→
    85→/* Repository instance (singleton inside this process) */
    86→static PaletteRepository g_repo;
    87→
    88→/* --------------------- repository (thread-safe) --------------------------- */
    89→static void
    90→repo_init(PaletteRepository *repo)
    91→{
    92→    memset(repo, 0, sizeof(*repo));
    93→    pthread_mutex_init(&repo->lock, NULL);
    94→}
    95→
    96→static void
    97→repo_destroy(PaletteRepository *repo)
    98→{
    99→    pthread_mutex_lock(&repo->lock);
   100→    for (size_t i = 0; i < repo->count; ++i)
   101→        free(repo->palettes[i]);
   102→    pthread_mutex_unlock(&repo->lock);
   103→    pthread_mutex_destroy(&repo->lock);
   104→}
   105→
   106→static int
   107→repo_add(PaletteRepository *repo, const Palette *p_in)
   108→{
   109→    int rc = -1;
   110→    pthread_mutex_lock(&repo->lock);
   111→    if (repo->count < MAX_PALETTES) {
   112→        Palette *copy = malloc(sizeof(*copy));
   113→        if (copy) {
   114→            *copy = *p_in;
   115→            repo->palettes[repo->count++] = copy;
   116→            rc = 0;
   117→        }
   118→    }
   119→    pthread_mutex_unlock(&repo->lock);
   120→    return rc;
   121→}
   122→
   123→static size_t
   124→repo_get_paginated(PaletteRepository *repo,
   125→                   size_t offset,
   126→                   size_t limit,
   127→                   Palette **out_buf,
   128→                   size_t  buf_len)
   129→{
   130→    size_t written = 0;
   131→
   132→    pthread_mutex_lock(&repo->lock);
   133→    if (offset < repo->count) {
   134→        const size_t avail = repo->count - offset;
   135→        const size_t n     = (limit < avail ? limit : avail);
   136→        for (size_t i = 0; i < n && i < buf_len; ++i)
   137→            out_buf[written++] = repo->palettes[offset + i];
   138→    }
   139→    pthread_mutex_unlock(&repo->lock);
   140→
   141→    return written;
   142→}
