   144→/* -------------------------------------------------------------------------- */
   145→/*                           Utility functions                                */
   146→/* -------------------------------------------------------------------------- */
   147→/* Very small UUIDv4 generator (pseudo-random).  NOT CRYPTO-SAFE.             */
   148→static void
   149→uuid_generate(char out[UUID_LEN + 1])
   150→{
   151→    static const char *hex = "0123456789abcdef";
   152→    uint8_t rnd[16];
   153→    for (size_t i = 0; i < sizeof(rnd); ++i)
   154→        rnd[i] = (uint8_t)(rand() % 256);
   155→
   156→    rnd[6] = (rnd[6] & 0x0F) | 0x40; /* version 4 */
   157→    rnd[8] = (rnd[8] & 0x3F) | 0x80; /* variant 1 */
   158→
   159→    snprintf(out, UUID_LEN + 1,
   160→             "%02x%02x%02x%02x-"
   161→             "%02x%02x-"
   162→             "%02x%02x-"
   163→             "%02x%02x-"
   164→             "%02x%02x%02x%02x%02x%02x",
   165→             rnd[0], rnd[1], rnd[2], rnd[3],
   166→             rnd[4], rnd[5],
   167→             rnd[6], rnd[7],
   168→             rnd[8], rnd[9],
   169→             rnd[10], rnd[11], rnd[12], rnd[13], rnd[14], rnd[15]);
   170→}
   171→
   172→/* Parse size_t from a string safely; returns default_val on error */
   173→static size_t
   174→str_to_sizet(const char *s, size_t default_val)
   175→{
   176→    if (!s) return default_val;
   177→    char *endptr = NULL;
   178→    unsigned long v = strtoul(s, &endptr, 10);
   179→    return (endptr != s && *endptr == '\0') ? (size_t)v : default_val;
   180→}
