   182→/* -------------------------------------------------------------------------- */
   183→/*                          HTTP / MicroHTTPD layer                           */
   184→/* -------------------------------------------------------------------------- */
   185→
   186→/* Connection specific data used to aggregate POST payloads */
   187→typedef struct {
   188→    char  *body;
   189→    size_t body_size;
   190→    size_t body_cap;
   191→} ConnInfo;
   192→
   193→static void
   194→conninfo_free_callback(void *cls, struct MHD_Connection *connection,
   195→                       void **con_cls, enum MHD_RequestTerminationCode toe)
   196→{
   197→    (void)cls; (void)connection; (void)toe;
   198→    ConnInfo *ci = *con_cls;
   199→    if (ci) {
   200→        free(ci->body);
   201→        free(ci);
   202→        *con_cls = NULL;
   203→    }
   204→}
   205→
   206→/* Append incoming data to the buffer, auto-expanding */
   207→static bool
   208→conninfo_append(ConnInfo *ci, const char *data, size_t size)
   209→{
   210→    if (size == 0) return true;
   211→    if (ci->body_size + size + 1 > ci->body_cap) {
   212→        size_t new_cap = (ci->body_cap ? ci->body_cap * 2 : 1024);
   213→        while (new_cap < ci->body_size + size + 1)
   214→            new_cap *= 2;
   215→        char *tmp = realloc(ci->body, new_cap);
   216→        if (!tmp) return false;
   217→        ci->body      = tmp;
   218→        ci->body_cap  = new_cap;
   219→    }
   220→    memcpy(ci->body + ci->body_size, data, size);
   221→    ci->body_size += size;
   222→    ci->body[ci->body_size] = '\0';
   223→    return true;
   224→}
