   226→/* --------------------------- REST Handlers -------------------------------- */
   227→static struct MHD_Response *
   228→json_response(cJSON *json, int status_code)
   229→{
   230→    char *json_str = cJSON_PrintUnformatted(json);
   231→    cJSON_Delete(json);
   232→    if (!json_str) return NULL;
   233→
   234→    struct MHD_Response *resp =
   235→        MHD_create_response_from_buffer(strlen(json_str),
   236→                                        json_str,
   237→                                        MHD_RESPMEM_MUST_FREE);
   238→    if (!resp) {
   239→        free(json_str);
   240→        return NULL;
   241→    }
   242→
   243→    MHD_add_response_header(resp, "Content-Type", "application/json");
   244→    MHD_add_response_header(resp, "Cache-Control", "no-store");
   245→    MHD_add_response_header(resp, "Connection", "close");
   246→    return resp;
   247→}
