   249→static int
   250→handle_healthz(struct MHD_Connection *connection)
   251→{
   252→    const char *ok = "ok";
   253→    struct MHD_Response *resp =
   254→        MHD_create_response_from_buffer(strlen(ok),
   255→                                        (void *)ok,
   256→                                        MHD_RESPMEM_PERSISTENT);
   257→    if (!resp) return MHD_NO;
   258→    int ret = MHD_queue_response(connection, MHD_HTTP_OK, resp);
   259→    MHD_destroy_response(resp);
   260→    return ret;
   261→}
