   263→static int
   264→handle_get_palettes(struct MHD_Connection *connection,
   265→                    const char           *url)
   266→{
   267→    (void)url;
   268→    size_t limit  = str_to_sizet(MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "limit"), 10);
   269→    size_t offset = str_to_sizet(MHD_lookup_connection_value(connection, MHD_GET_ARGUMENT_KIND, "offset"), 0);
   270→
   271→    if (limit == 0 || limit > 100)
   272→        limit = 100; /* enforce server-side caps */
   273→
   274→    Palette *stack_buf[128]; /* limit capped at 100 so safe */
   275→    const size_t n = repo_get_paginated(&g_repo, offset, limit, stack_buf, 128);
   276→
   277→    cJSON *root  = cJSON_CreateObject();
   278→    cJSON *items = cJSON_AddArrayToObject(root, "items");
   279→
   280→    for (size_t i = 0; i < n; ++i) {
   281→        Palette *p = stack_buf[i];
   282→        cJSON *jpal = cJSON_CreateObject();
   283→        cJSON_AddStringToObject(jpal, "id", p->id);
