   494→        else if (strcmp(lvl, "LOG_INFO") == 0)    CURRENT_LOG_LEVEL = LOG_INFO;
   495→        else if (strcmp(lvl, "LOG_WARNING") == 0) CURRENT_LOG_LEVEL = LOG_WARNING;
