   122→/* ------------------------------------------------------------------------- */
   123→/* Token Bucket Rate-Limiting                                                */
   124→/* ------------------------------------------------------------------------- */
   125→typedef struct {
   126→    uint64_t last_refill_ms;
   127→    int64_t  tokens;
   128→    pthread_mutex_t mtx;
   129→} bucket_t;
   130→
   131→static bucket_t *
   132→bucket_create(void)
   133→{
   134→    bucket_t *b = calloc(1, sizeof(*b));
   135→    b->last_refill_ms = now_millis();
   136→    b->tokens         = TOKEN_BUCKET_CAP;
   137→    pthread_mutex_init(&b->mtx, NULL);
   138→    return b;
   139→}
   140→
   141→static bool
   142→bucket_take(bucket_t *b)
   143→{
   144→    bool allowed = false;
   145→    pthread_mutex_lock(&b->mtx);
   146→
   147→    uint64_t now = now_millis();
   148→    uint64_t elapsed = now - b->last_refill_ms;
   149→
   150→    if (elapsed >= 1000) {
   151→        int64_t refill = (elapsed / 1000) * TOKEN_BUCKET_RATE;
   152→        if (refill > 0) {
   153→            b->tokens = (b->tokens + refill > TOKEN_BUCKET_CAP)
   154→                      ? TOKEN_BUCKET_CAP
   155→                      : b->tokens + refill;
   156→            b->last_refill_ms = now;
   157→        }
   158→    }
   159→
   160→    if (b->tokens > 0) {
   161→        b->tokens--;
   162→        allowed = true;
   163→    }
   164→
   165→    pthread_mutex_unlock(&b->mtx);
   166→    return allowed;
   167→}
