   169→/* Very thin IP→bucket map (open addressing). Not built for huge cardinality,
   170→ * but sufficient for small public endpoints. */
   171→#define BUCKET_MAP_SZ  1024
   172→typedef struct {
   173→    char     *ip;
   174→    bucket_t *bucket;
   175→} bucket_map_slot_t;
   176→
   177→static bucket_map_slot_t bucket_map[BUCKET_MAP_SZ];
   178→static pthread_mutex_t   bucket_map_mtx = PTHREAD_MUTEX_INITIALIZER;
   179→
   180→static bucket_t *
   181→rate_limit_get_bucket(const char *ip)
   182→{
   183→    uint32_t h = 0;
   184→    for (const char *p = ip; *p; ++p)
   185→        h = (h * 33u) ^ (unsigned)(*p);
   186→    uint32_t idx = h % BUCKET_MAP_SZ;
   187→
   188→    pthread_mutex_lock(&bucket_map_mtx);
   189→    for (uint32_t i = 0; i < BUCKET_MAP_SZ; ++i) {
   190→        uint32_t probe = (idx + i) % BUCKET_MAP_SZ;
   191→
   192→        if (bucket_map[probe].ip == NULL) {
   193→            /* create slot */
   194→            bucket_map[probe].ip     = strdup(ip);
   195→            bucket_map[probe].bucket = bucket_create();
   196→            pthread_mutex_unlock(&bucket_map_mtx);
   197→            return bucket_map[probe].bucket;
   198→        }
   199→
   200→        if (strcmp(bucket_map[probe].ip, ip) == 0) {
   201→            pthread_mutex_unlock(&bucket_map_mtx);
   202→            return bucket_map[probe].bucket;
   203→        }
   204→    }
   205→    /* Fallback (evict) */
   206→    pthread_mutex_unlock(&bucket_map_mtx);
   207→    return bucket_create();
   208→}
