   210→/* ------------------------------------------------------------------------- */
   211→/* Up-stream Proxy Helpers (libcurl)                                         */
   212→/* ------------------------------------------------------------------------- */
   213→typedef struct {
   214→    char *ptr;
   215→    size_t len;
   216→} dynbuf_t;
   217→
   218→static size_t
   219→curl_write_cb(char *data, size_t size, size_t nmemb, void *userdata)
   220→{
   221→    size_t real = size * nmemb;
   222→    dynbuf_t *db = userdata;
   223→
   224→    char *tmp = realloc(db->ptr, db->len + real + 1);
   225→    if (!tmp) return 0;
   226→
   227→    memcpy(tmp + db->len, data, real);
   228→    db->ptr = tmp;
   229→    db->len += real;
   230→    db->ptr[db->len] = '\0';
   231→    return real;
   232→}
   233→
   234→static int
   235→proxy_post(const char *url, const char *body, struct MHD_Response **resp, unsigned int *status)
   236→{
   237→    CURL *curl = curl_easy_init();
   238→    if (!curl) return -1;
   239→
   240→    dynbuf_t db = { .ptr = NULL, .len = 0 };
   241→    struct curl_slist *hdrs = NULL;
   242→    hdrs = curl_slist_append(hdrs, "Content-Type: application/json");
   243→
   244→    curl_easy_setopt(curl, CURLOPT_URL, url);
   245→    curl_easy_setopt(curl, CURLOPT_POSTFIELDS, body);
   246→    curl_easy_setopt(curl, CURLOPT_HTTPHEADER, hdrs);
   247→    curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, curl_write_cb);
   248→    curl_easy_setopt(curl, CURLOPT_WRITEDATA, &db);
   249→    curl_easy_setopt(curl, CURLOPT_TIMEOUT, 5L);
   250→
   251→    CURLcode ret = curl_easy_perform(curl);
   252→    long http_code = 502;
   253→    curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &http_code);
   254→
   255→    curl_slist_free_all(hdrs);
   256→    curl_easy_cleanup(curl);
   257→
   258→    if (ret != CURLE_OK) {
   259→        syslog(LOG_ERR, "curl failed: %s", curl_easy_strerror(ret));
   260→        return -1;
   261→    }
   262→
   263→    *status = (unsigned int)http_code;
   264→    *resp   = MHD_create_response_from_buffer(db.len, db.ptr, MHD_RESPMEM_MUST_FREE);
   265→    return 0;
   266→}
