   306→                          "{\"error\":\"empty body\"}");
   307→    }
   308→
   309→    cJSON *json = cJSON_ParseWithLength(rctx->body, rctx->body_size);
   310→    if (!json) {
   311→        return reply_json(conn, MHD_HTTP_BAD_REQUEST,
