   314→
   315→    cJSON *query = cJSON_GetObjectItemCaseSensitive(json, "query");
   316→    if (!cJSON_IsString(query) || query->valuestring[0] == '\0') {
   317→        cJSON_Delete(json);
   318→        return reply_json(conn, MHD_HTTP_BAD_REQUEST,
